import { useEffect, useState } from 'react';
import {
  type DateValue,
  DatePicker as AriaDatePicker,
} from 'react-aria-components';
import { Calendar as BaseCalendar } from '@/vendor/untitled-ui/application/date-picker/calendar';
import { WithDataId } from '@/types/withDataId';

export type CalendarProps = React.ComponentProps<typeof BaseCalendar> &
  WithDataId;

export function Calendar({
  value,
  defaultValue,
  onChange,
  ...rest
}: CalendarProps) {
  const [focusedValue, setFocusedValue] = useState<DateValue | undefined>(
    value ?? defaultValue ?? undefined,
  );

  useEffect(() => {
    setFocusedValue(value ?? undefined);
  }, [value]);

  return (
    <AriaDatePicker
      aria-label="calendar"
      value={value}
      defaultValue={defaultValue}
      onChange={(date) => {
        if (date) {
          onChange?.(date);
          setFocusedValue(date);
        }
      }}
    >
      <BaseCalendar
        {...rest}
        focusedValue={focusedValue}
        onFocusChange={setFocusedValue}
      />
    </AriaDatePicker>
  );
}
